mapper.select:
select * from ( select b.orderid, DATE_FORMAT(b.basedate,'%Y/%m/%d') as basedate , b.runcnt, b.jobid, b.version, b.jobname, b.system, b.policy_id, b.keymap_id, b.jobtype, b.runtype, b.calendar, b.time, b.status, b.confirmflag, b.holdflag, b.forceokflag, b.killflag , DATE_FORMAT(b.eststarttime,'%Y/%m/%d %H:%i:%s') as eststarttime, b.runningtime, DATE_FORMAT(b.realstarttime,'%Y/%m/%d %H:%i:%s') as realstarttime, DATE_FORMAT(b.realendtime,'%Y/%m/%d %H:%i:%s') as realendtime, DATE_FORMAT(b.orderdate,'%Y/%m/%d %H:%i:%s') as orderdate , b.orderuserid , DATE_FORMAT(a.archive_date,'%Y/%m/%d %H:%i:%s') as archive_date, DATE_FORMAT(a.delete_date,'%Y/%m/%d %H:%i:%s') as delete_date /*, ( select MAX(upddate) from cotdl.tbl_piirestore r where r.old_orderid=a.orderid and r.custid = a.custid and r.status='Ended OK') as restore_date*/ , DATE_FORMAT(a.restore_date,'%Y/%m/%d %H:%i:%s') as restore_date , DATE_FORMAT(a.arc_del_date,'%Y/%m/%d') as arc_del_date , DATE_FORMAT(a.last_base_date,'%Y/%m/%d') as last_base_date , DATE_FORMAT(a.expected_arc_del_date,'%Y/%m/%d') as expected_arc_del_date , a.custid, a.cust_nm, a.birth_dt, a.rsdnt_altrntv_id, a.cust_pin, a.exclude_reason from cotdl.tbl_piiextract a, cotdl.tbl_piiorder b, cotdl.tbl_piiorderstep c where 1 = 1 and a.orderid=b.orderid and a.archive_date is not null and a.delete_date is not null and b.status = 'Ended OK' and c.orderid=b.orderid and c.steptype = 'EXE_ARCHIVE'
limit #{offset}, #{amount}
) a order by orderid desc, custid
